module mux8to1 (
    input [7:0] input_data,    // 8 input_data inputs
    input [2:0] sel,     // 3 selection inputs
    output reg out       // output
);
    always @(*) begin
        case (sel)
            3'b000: out = input_data[0];
            3'b001: out = input_data[1];
            3'b010: out = input_data[2];
            3'b011: out = input_data[3];
            3'b100: out = input_data[4];
            3'b101: out = input_data[5];
            3'b110: out = input_data[6];
            3'b111: out = input_data[7];
            default: out = 1'b0; // default case
        endcase
    end
endmodule
